package com.nullPointerSociety.elfogon.ui.screens.recipes.detailsimport android.annotation.SuppressLintimport android.os.Buildimport androidx.annotation.RequiresApiimport androidx.compose.foundation.layout.PaddingValuesimport androidx.compose.foundation.layout.fillMaxSizeimport androidx.compose.foundation.lazy.LazyColumnimport androidx.compose.foundation.lazy.LazyListStateimport androidx.compose.runtime.Composableimport androidx.compose.runtime.MutableStateimport androidx.compose.ui.Modifierimport androidx.compose.ui.unit.dpimport com.nullPointerSociety.elfogon.ui.components.recipeDetailsScreen.Ingredientsimport com.nullPointerSociety.elfogon.ui.components.recipeDetailsScreen.RecipeDetailsTitleimport com.nullPointerSociety.elfogon.ui.components.recipeDetailsScreen.RecipeImgimport com.nullPointerSociety.elfogon.ui.components.recipeDetailsScreen.RecipeSummaryimport com.nullPointerSociety.elfogon.ui.components.recipeDetailsScreen.Stepsimport com.nullPointerSociety.elfogon.ui.navigation.Routes@RequiresApi(Build.VERSION_CODES.N)@Composablefun RecipeDetailsScreen(    id: Int,    viewModel: RecipeDetailsViewModel,    onBack: () -> Unit,    @SuppressLint("ModifierParameter") modifier: Modifier = Modifier,    specifyRoute: MutableState<String>,    titleScreen: MutableState<String>,    scrollState: LazyListState) {    val detailRecipe = viewModel.getRecipeById(id)    specifyRoute.value = Routes.DETAILS_RECIPE    titleScreen.value = detailRecipe?.title.toString()    LazyColumn(        state = scrollState,        contentPadding = PaddingValues(bottom = 140.dp),        modifier = modifier            .fillMaxSize()    ) {        item {            RecipeDetailsTitle(detailRecipe?.title, detailRecipe?.readyInMinutes)        }        item {            RecipeImg(detailRecipe?.image, detailRecipe?.title)        }        item {            RecipeSummary(detailRecipe?.summary)        }        item {            Ingredients(detailRecipe?.extendedIngredients ?: emptyList())        }        item {            Steps(detailRecipe?.analyzedInstructions ?: emptyList())        }    }}